import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void mixedHistogram() {
        int[] result = new Solution().categoryHistogram(
            new String[]{"dining", "groceries", "dining", "fuel"},
            new String[]{"dining", "fuel", "travel"}
        );
        assertArrayEquals(new int[]{2, 1, 0}, result);
    }

    @Test
    void emptyCategories() {
        int[] result = new Solution().categoryHistogram(
            new String[]{},
            new String[]{"anything"}
        );
        assertArrayEquals(new int[]{0}, result);
    }

    @Test
    void singleCategoryTwoQueries() {
        int[] result = new Solution().categoryHistogram(
            new String[]{"a"},
            new String[]{"a", "b"}
        );
        assertArrayEquals(new int[]{1, 0}, result);
    }

    @Test
    void emptyQuery() {
        int[] result = new Solution().categoryHistogram(
            new String[]{"a", "b"},
            new String[]{}
        );
        assertArrayEquals(new int[]{}, result);
    }
}
